import{_ as t,o,c as n,ag as a}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"Connecting to the Patcher","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/connecting.md","filePath":"getting-started/connecting.md"}'),r={name:"getting-started/connecting.md"};function i(l,e,c,s,h,d){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="connecting-to-the-patcher" tabindex="-1">Connecting to the Patcher <a class="header-anchor" href="#connecting-to-the-patcher" aria-label="Permalink to &quot;Connecting to the Patcher&quot;">​</a></h1><p>The patcher communicates with your Smart Contact Mic over USB using Web Serial. No drivers or plugins are needed -- it runs entirely in your browser.</p><h2 id="connect" tabindex="-1">Connect <a class="header-anchor" href="#connect" aria-label="Permalink to &quot;Connect&quot;">​</a></h2><ol><li>Open the patcher at <a href="https://soniphorm.com/patcher" target="_blank" rel="noreferrer">soniphorm.com/patcher</a></li><li>Plug your board in via USB-C</li><li>Click the <strong>Connect</strong> button in the toolbar (plug icon)</li><li>A browser dialog will appear listing available serial ports -- select your ESP32-S3 device</li><li>The connect button will change to show a connected state</li></ol><div class="info custom-block"><p class="custom-block-title">Browser Support</p><p>Web Serial is supported in <strong>Chrome</strong>, <strong>Edge</strong>, and <strong>Opera</strong> on desktop. It is not available in Firefox, Safari, or any mobile browser. On mobile devices, you can use BLE (Bluetooth) to connect instead.</p></div><h2 id="verify-the-connection" tabindex="-1">Verify the Connection <a class="header-anchor" href="#verify-the-connection" aria-label="Permalink to &quot;Verify the Connection&quot;">​</a></h2><p>Once connected, open the <strong>Serial Console</strong> from the toolbar. Type <code>STATUS</code> and press Enter. You should see a response showing the firmware version, CPU usage, and current patch info.</p><h2 id="upload-a-patch" tabindex="-1">Upload a Patch <a class="header-anchor" href="#upload-a-patch" aria-label="Permalink to &quot;Upload a Patch&quot;">​</a></h2><p>With the connection active:</p><ol><li>Build a patch on the canvas (or load an example from the menu)</li><li>Click the <strong>Upload</strong> button in the toolbar (arrow icon)</li><li>The patch uploads as JSON over serial -- you&#39;ll hear the result immediately</li><li>The serial console shows upload progress and confirmation</li></ol><h2 id="disconnect" tabindex="-1">Disconnect <a class="header-anchor" href="#disconnect" aria-label="Permalink to &quot;Disconnect&quot;">​</a></h2><p>Click the connect button again to disconnect, or simply unplug the USB cable. The board continues running the last uploaded patch independently.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Solution</th></tr></thead><tbody><tr><td>No ports listed in the dialog</td><td>Check the USB cable. Press RESET on the board. Try a different USB port.</td></tr><tr><td>Connection drops frequently</td><td>Use a shorter USB cable. Avoid USB hubs.</td></tr><tr><td>Upload fails or times out</td><td>Open the serial console and check for error messages. Try disconnecting and reconnecting.</td></tr><tr><td>&quot;Failed to open serial port&quot;</td><td>Another app (Arduino IDE, serial terminal) may be using the port. Close it and retry.</td></tr></tbody></table>',14)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
